let aiNode = $("🤖 AI: Profile").first().json;
let content = aiNode.message?.content || aiNode.text;
let charAi;
if (typeof content === 'object') {
  charAi = content;
} else if (typeof content === 'string') {
  try {
    charAi = JSON.parse(content.replace(/```json/gi, '').replace(/```/g, '').trim());
  } catch(e) {
    charAi = {};
  }
} else {
  charAi = aiNode; 
}

const form = $("🗓️ Trigger: Form").first().json;

return [{
  json: {
    Name: form["Influencer Name"],
    Handle: form["Instagram Handle"],
    Niche: form["Niche"],
    Gender: "Generated",
    Age: "24",
    Location: "India",
    Personality: charAi.personality || "",
    Aesthetic: charAi.aesthetic || "",
    Bio: charAi.bio || "",
    "Hashtag Bank": charAi.hashtags || "",
    Timestamp: new Date().toISOString()
  }
}];

let aiNode = $("🤖 AI: 30-Day Calendar").first().json;
let content = aiNode.message?.content || aiNode.text;
let calAi;

if (typeof content === 'object') {
  calAi = content;
} else if (typeof content === 'string') {
  let clean = content.replace(/```json/gi, '').replace(/```/g, '').trim();
  if (clean.startsWith("[") && !clean.endsWith("]")) {
    clean = clean.replace(/,\s*$/, '') + "}]"; 
  }
  try {
    calAi = JSON.parse(clean);
  } catch(e) {
    calAi = [];
  }
} else {
  calAi = aiNode;
}

const form = $("🗓️ Trigger: Form").first().json;
const influencer = form["Influencer Name"] + " (" + form["Instagram Handle"] + ")";

if (!Array.isArray(calAi)) return [];

return calAi.map(day => ({ json: {
  Influencer: influencer,
  Day: day.day || "",
  Type: day.type || "",
  "Photo Description": day.photo_description || "",
  "Ideogram Prompt": day.ideogram_prompt || "",
  Caption: day.caption || "",
  Hashtags: day.hashtags || "",
  "Posting Time": day.posting_time || "",
  "Image Status": "Not Generated",
  "Video Status": "Not Generated",
  Posted: "No"
} }));
